export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (!arg.startsWith('--')) result._.push(arg)
    else result[arg.slice(2)] = true
  }
  return result
}

import test from 'node:test'
import assert from 'node:assert/strict'
import { parseArgs } from './src/parseArgs.mjs'

test('parseArgs handles booleans, values, equals syntax, and positionals', () => {
  assert.deepEqual(parseArgs(['--verbose', '--count', '3', '--output=dist', 'src/index.js']), {
    _: ['src/index.js'],
    verbose: true,
    count: '3',
    output: 'dist'
  })
})

content.thinking:
Now I understand the problem:

1. Current implementation is too simplistic - it just treats everything starting with `--` as a boolean flag
2. The test expects:
   - `--verbose` → `verbose: true` (boolean flag)
   - `--count 3` → `count: '3'` (flag with value following it)
   - `--output=dist` → `output: 'dist'` (flag=value syntax)
   - `src/index.js` → `_: ['src/index.js']` (positional argument)

The current implementation fails because:
1. It doesn't handle `--key value` syntax (separate argument)
2. It doesn't handle `--key=value` syntax properly
3. It doesn't treat non-`--` arguments as positional (it does this for anything not starting with `--`, which is correct for positionals)

Let me write a corrected version that handles all these cases:

```javascript
export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]

    // Positional arguments (don't start with --)
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }

    // Parse --key=value syntax
    if (arg.includes('=')) {
      const [key, value] = arg.split('=', 2)
      result[key] = value
      continue
    }

    // --key (boolean or needs next value)
    const key = arg.slice(2)
    // If next arg doesn't start with --, it's the value
    if (index + 1 < argv.length && !argv[index + 1].startsWith('--')) {
      result[key] = argv[index + 1]
      index += 1 // Skip the next argument
    } else {
      result[key] = true
    }
  }
  return result
}
```

This implementation correctly handles boolean flags, assigns values for flags followed by non-flag arguments, and captures the key-value pairs from the equals syntax.

